<?php
 namespace WPAICG\AutoGPT\Cron\Init; use WPAICG\aipkit_dashboard; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Event_Processor; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Scheduler; if (!defined('ABSPATH')) { exit; } function ensure_dashboard_loaded_logic(): bool { if (!class_exists(aipkit_dashboard::class)) { $dashboard_path = WPAICG_PLUGIN_DIR . 'classes/dashboard/class-aipkit_dashboard.php'; if (file_exists($dashboard_path)) { require_once $dashboard_path; } else { return false; } } return true; } function check_module_status_logic(string $main_cron_hook): bool { $option_key_autogpt_active = 'aipkit_autogpt_module_was_active'; $module_settings = aipkit_dashboard::get_module_settings(); $is_autogpt_currently_active = !empty($module_settings['autogpt']); $was_autogpt_active = (bool) get_option($option_key_autogpt_active, false); if (!$is_autogpt_currently_active) { if ($was_autogpt_active && wp_next_scheduled($main_cron_hook)) { wp_clear_scheduled_hook($main_cron_hook); } update_option($option_key_autogpt_active, false, 'no'); return false; } if (!$was_autogpt_active) { update_option($option_key_autogpt_active, true, 'no'); } return true; } function ensure_table_exists_logic(\wpdb $wpdb, string $tasks_table_name, string $main_cron_hook): bool { $table_exists = $wpdb->get_var($wpdb->prepare("SHOW TABLES LIKE %s", $tasks_table_name)); if ($table_exists !== $tasks_table_name) { if (wp_next_scheduled($main_cron_hook)) { wp_clear_scheduled_hook($main_cron_hook); } return false; } return true; } function aipkit_get_validated_table_identifier_logic(string $table_name): string { $table_name = trim($table_name); if ($table_name === '' || !preg_match('/^[A-Za-z0-9_]+$/', $table_name)) { return ''; } return '`' . $table_name . '`'; } function evaluate_status_flags_logic(\wpdb $wpdb, string $tasks_table_name): array { $option_key_tasks_exist = 'aipkit_active_tasks_exist'; $queue_table_name = $wpdb->prefix . 'aipkit_automated_task_queue'; $tasks_table_identifier = aipkit_get_validated_table_identifier_logic($tasks_table_name); $queue_table_identifier = aipkit_get_validated_table_identifier_logic($queue_table_name); if ($tasks_table_identifier === '' || $queue_table_identifier === '') { return [ 'active_task_count' => 0, 'pending_queue_count' => 0, 'did_active_tasks_exist' => (bool) get_option($option_key_tasks_exist, false), ]; } $active_task_count = (int) $wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM {$tasks_table_identifier} WHERE status = %s", 'active')); $pending_queue_count = (int) $wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM {$queue_table_identifier} WHERE status = %s", 'pending')); $did_active_tasks_exist = (bool) get_option($option_key_tasks_exist, false); return [ 'active_task_count' => $active_task_count, 'pending_queue_count' => $pending_queue_count, 'did_active_tasks_exist' => $did_active_tasks_exist, ]; } function register_main_cron_hook_logic(string $main_cron_hook, int $active_task_count, int $pending_queue_count, bool $did_active_tasks_exist): void { $option_key_tasks_exist = 'aipkit_active_tasks_exist'; $has_work_to_do = ($active_task_count > 0) || ($pending_queue_count > 0); if (!$has_work_to_do) { if ($did_active_tasks_exist && wp_next_scheduled($main_cron_hook)) { wp_clear_scheduled_hook($main_cron_hook); } update_option($option_key_tasks_exist, false, 'no'); } else { if (!$did_active_tasks_exist) { update_option($option_key_tasks_exist, true, 'no'); } if (!wp_next_scheduled($main_cron_hook)) { wp_schedule_event(time(), 'hourly', $main_cron_hook); } } } function attach_main_hook_action_logic(string $main_cron_hook): void { if (!class_exists(AIPKit_Automated_Task_Event_Processor::class)) { return; } if (!has_action($main_cron_hook, [AIPKit_Automated_Task_Event_Processor::class, 'process_task_queue_event'])) { add_action($main_cron_hook, [AIPKit_Automated_Task_Event_Processor::class, 'process_task_queue_event']); } } function attach_individual_task_hooks_logic(\wpdb $wpdb, string $tasks_table_name): void { if (!class_exists(AIPKit_Automated_Task_Scheduler::class) || !class_exists(AIPKit_Automated_Task_Event_Processor::class)) { return; } $all_tasks = $wpdb->get_results("SELECT id FROM " . esc_sql($tasks_table_name), ARRAY_A); if ($all_tasks) { foreach ($all_tasks as $task) { $task_id = (int)$task['id']; $task_specific_hook = AIPKit_Automated_Task_Scheduler::get_task_specific_cron_hook($task_id); if (!has_action($task_specific_hook, [AIPKit_Automated_Task_Event_Processor::class, 'trigger_task_event'])) { add_action($task_specific_hook, [AIPKit_Automated_Task_Event_Processor::class, 'trigger_task_event'], 10, 1); } } } } 